11	// ----- classifier tests -----
12	
13	func TestParseAcceptance_NumberedItems(t *testing.T) {
14		in := `1. First AC line.
15	2. Second AC line.
16	3. Third AC line.`
17		items := ParseAcceptance(in)
18		if len(items) != 3 {
19			t.Fatalf("expected 3 items, got %d", len(items))
20		}
21		for i, it := range items {
22			if it.AC != i+1 {
23				t.Errorf("item %d: expected AC=%d, got %d", i, i+1, it.AC)
24			}
25		}
26	}
27	
28	func TestClassify_TestNameAC(t *testing.T) {
29		k, name := classify("TestFooBar passes against fixture X")
30		if k != KindTestName {
31			t.Errorf("kind: want %s, got %s", KindTestName, k)
32		}
33		if name != "TestFooBar" {
34			t.Errorf("name: want TestFooBar, got %q", name)
35		}
36	}
37	
38	func TestClassify_SymbolAC_Backtick(t *testing.T) {
39		k, name := classify("`RemovedExecutionDirs` counter is incremented per delete")
40		if k != KindSymbol {
41			t.Errorf("kind: want %s, got %s", KindSymbol, k)
42		}
43		if name != "RemovedExecutionDirs" {
44			t.Errorf("name: want RemovedExecutionDirs, got %q", name)
45		}
46	}
47	
48	func TestClassify_NegativeAC(t *testing.T) {
49		k, name := classify("Land() no longer calls `git.Fetch` directly")
50		if k != KindNegative {
51			t.Errorf("kind: want %s, got %s", KindNegative, k)
52		}
53		if name != "git.Fetch" {
54			t.Errorf("name: want git.Fetch, got %q", name)
55		}
56	}
57	
58	func TestClassify_BuildGate(t *testing.T) {
59		k, _ := classify("lefthook run pre-commit passes")
60		if k != KindBuildGate {
61			t.Errorf("kind: want %s, got %s", KindBuildGate, k)
62		}
63	}
64	
65	func TestClassify_Mechanical_Rename(t *testing.T) {
66		k, _ := classify("rename module path from x to y")
67		if k != KindMechanical {
68			t.Errorf("kind: want %s, got %s", KindMechanical, k)
69		}
