79	// ----- evaluator tests (using injected hooks) -----
80	
81	func ctxWithHooks(tb testing.TB, runTest func(name string, packages []string) (bool, string, error), grep func(symbol string) (int, string, error), diff func(symbol string) (int, error)) Context {
82		tb.Helper()
83		return Context{
84			WorkingDir: ".",
85			RunTest:    runTest,
86			GitGrep:    grep,
87			DiffHits:   diff,
88		}
89	}
90	
91	func TestACCheck_TestNameAC_Passes(t *testing.T) {
92		item := Item{AC: 1, Text: "TestFoo passes", Kind: KindTestName, Name: "TestFoo"}
93		ctx := ctxWithHooks(t,
94			func(name string, packages []string) (bool, string, error) {
95				if name != "TestFoo" {
96					return false, "wrong name", nil
97				}
98				return true, "ok 0.04s", nil
99			}, nil, nil)
100		e := evaluateOne(item, ctx)
101		if e.Result != ResultPass {
102			t.Fatalf("expected pass, got %s (%s)", e.Result, e.Evidence)
103		}
104	}
105	
106	func TestACCheck_TestNameAC_Renamed_WithAlias(t *testing.T) {
107		item := Item{AC: 1, Text: "TestFooBar passes", Kind: KindTestName, Name: "TestFooBar"}
108		ctx := ctxWithHooks(t,
109			func(name string, packages []string) (bool, string, error) {
110				// Should be invoked with the alias, not the original.
111				if name != "TestFoo/bar" {
112					return false, "expected alias invocation", nil
113				}
114				return true, "ok via alias", nil
115			}, nil, nil)
116		ctx.Aliases = map[int]string{1: "TestFoo/bar"}
117		entries := Evaluate([]Item{item}, ctx)
118		if entries[0].Result != ResultPass {
119			t.Fatalf("expected pass with alias, got %s (%s)", entries[0].Result, entries[0].Evidence)
120		}
121	}
