288	// that named missing symbols and tests.
289	func TestACCheck_RegressionFakeRetainDays(t *testing.T) {
290		// Mimic the bead's acceptance text (abbreviated).
291		acceptance := `1. cli/internal/agent/execution_cleanup.go has a ` + "`pruneOlderThan`" + ` helper.
292	2. ` + "`RemovedExecutionDirs`" + `, ` + "`RemovedAgentLogs`" + `, ` + "`RemovedWorkerDirs`" + ` counters are added.
293	3. Default RetainDays is 90 (not 7).
294	4. TestExecutionCleanup_DeletesOldAgentLogs passes.
295	5. lefthook run pre-commit passes.`
296		items := ParseAcceptance(acceptance)
297		if len(items) != 5 {
298			t.Fatalf("expected 5 items, got %d", len(items))
299		}
300	
301		// Simulate the fake-work diff: only types.go default value changed.
302		// No pruneOlderThan in the tree. No counters added. No test added.
303		ctx := Context{
304			RunTest: func(name string, _ []string) (bool, string, error) {
305				// No matching test exists in the fake diff.
306				return false, "[no tests to run]", nil
307			},
308			GitGrep: func(symbol string) (int, string, error) {
309				// None of the claimed symbols exist post-image.
310				return 0, "", nil
311			},
312			DiffHits: func(symbol string) (int, error) { return 0, nil },
313		}
314	
315		entries := Evaluate(items, ctx)
316		out := Aggregate("ddx-cccb4763", "test-replay", entries)
317	
318		// AC 1: pruneOlderThan symbol → fail (0 grep hits in post-image).
319		if entries[0].Result != ResultFail {
320			t.Errorf("AC #1 (pruneOlderThan): want fail, got %s — %s", entries[0].Result, entries[0].Evidence)
321		}
322		// AC 2: multiple counter symbols → fail.
323		if entries[1].Result != ResultFail {
324			t.Errorf("AC #2 (counters): want fail, got %s — %s", entries[1].Result, entries[1].Evidence)
325		}
326		// AC 3: default value (prose) → needs_judgment (not a symbol AC, not a fail).
327		if entries[2].Result == ResultPass {
328			t.Errorf("AC #3 (default 90): must not auto-pass; got %s", entries[2].Result)
329		}
330		// AC 4: TestExecutionCleanup_DeletesOldAgentLogs → fail (no matching test).
331		if entries[3].Result != ResultFail {
332			t.Errorf("AC #4 (test): want fail, got %s — %s", entries[3].Result, entries[3].Evidence)
333		}
334		// AC 5: build-gate → needs_judgment (orchestrator reports separately).
335		if entries[4].Result != ResultNeedsJudgment {
336			t.Errorf("AC #5 (lefthook): want needs_judgment, got %s", entries[4].Result)
337		}
338	
339		// Overall: fake-work must NOT register as all-pass.
340		if out.Summary.Fail < 2 {
341			t.Errorf("fake-work AC-check should produce ≥ 2 fails; got %+v", out.Summary)
342		}
343	
344		// Trace for humans reading test output.
345		var buf bytes.Buffer
346		_ = WriteHuman(&buf, out)
347		t.Logf("regression replay:\n%s", buf.String())
348	
349		// Make sure JSON shape round-trips through encoding/json correctly so
