438	// DefaultDiffHits returns a DiffHits hook that counts occurrences of symbol in
439	// `git diff <base>..HEAD` output. base may be empty (no diff filter).
440	func DefaultDiffHits(workingDir, base string) func(symbol string) (int, error) {
441		return func(symbol string) (int, error) {
442			if symbol == "" {
443				return 0, nil
444			}
445			args := []string{"diff"}
446			if base != "" {
447				args = append(args, base)
448			}
449			cmd := exec.Command("git", args...)
450			cmd.Dir = workingDir
451			out, err := cmd.Output()
452			if err != nil {
453				return 0, err
454			}
455			return strings.Count(string(out), symbol), nil
456		}
457	}
