)

// BeadStrictnessMode returns the reviewer strictness mode for a bead based on
// its labels. kind:fix/feat → strict; kind:refactor/chore → behavior-light;
// kind:doc/mechanical → mechanical. Defaults to strict when no kind label is
// present.
func BeadStrictnessMode(labels []string) StrictnessMode {
	for _, l := range labels {
		switch l {
		case "kind:fix", "kind:feat":
			return StrictnessStrict
		case "kind:refactor", "kind:chore":
			return StrictnessBehaviorLight
		case "kind:doc", "kind:mechanical":
			return StrictnessMechanical
		}
	}
	return StrictnessStrict
}

