// BuildCommitMessageFromResultFile reads the result.json artifact at resultPath
// and renders the canonical execute-bead iteration commit message from it.
// This is the file-sourced rendering path: callers must write result.json before
// calling this function. The message is deterministic for a given result.json —
// anyone can re-derive it from the tracked bundle without re-running the agent.
func BuildCommitMessageFromResultFile(resultPath string) (string, error) {
	raw, err := os.ReadFile(resultPath)
	if err != nil {
		return "", fmt.Errorf("reading result file %s: %w", resultPath, err)
	}
	var res ExecuteBeadResult
	if err := json.Unmarshal(raw, &res); err != nil {
		return "", fmt.Errorf("parsing result file %s: %w", resultPath, err)
	}
	return BuildIterationCommitMessage(&res), nil
}

// BuildACCheckTrailer formats the AC-Check: git trailer from an ac-check
// summary. The trailer value is a compact pass/fail/needs-judgment/error
// count string so the verdict is visible in `git log --oneline` trailers.
func BuildACCheckTrailer(s accheck.Summary) string {
	return fmt.Sprintf("AC-Check: pass=%d fail=%d needs-judgment=%d error=%d",
		s.Pass, s.Fail, s.NeedsJudgment, s.Error)
}

// ShouldAbortForACCheckFail returns true when the ac-check output contains
// at least one fail result AND the commit message does not carry an AC-Waive:
// trailer (indicating the operator has explicitly waived the failure).
func ShouldAbortForACCheckFail(output *accheck.Output, commitMsg string) bool {
	if output == nil || output.Summary.Fail == 0 {
		return false
	}
	for _, line := range strings.Split(commitMsg, "\n") {
		if strings.HasPrefix(strings.TrimSpace(line), "AC-Waive:") {
			return false
		}
	}
	return true
}

