package agent

import (
	"context"
	"encoding/json"
	"strings"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/bead/accheck"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestReviewer_RatifiesACCheck_AllPass_ApproveImplicit verifies that when
// ac-check.json shows all AC items passing, the assembled review prompt
// includes the <ac-check> section so the reviewer can ratify the mechanical
// results rather than re-grepping the diff independently.
func TestReviewer_RatifiesACCheck_AllPass_ApproveImplicit(t *testing.T) {
	b := &bead.Bead{
		ID:         "ddx-ratify-allpass",
		Title:      "add TestFoo to foo_test.go",
		Acceptance: "1. TestFoo passes\n2. cd cli && go test ./... green",
	}

	acOut := accheck.Output{
		SchemaVersion: 1,
		BeadID:        b.ID,
		Summary:       accheck.Summary{Pass: 1, NeedsJudgment: 1},
		Items: []accheck.Entry{
			{AC: 1, Kind: accheck.KindTestName, Name: "TestFoo", Result: accheck.ResultPass, Evidence: "test TestFoo passed"},
			{AC: 2, Kind: accheck.KindBuildGate, Result: accheck.ResultNeedsJudgment, Evidence: "build/gate AC; orchestrator reports exit code separately"},
		},
	}
	acJSON, err := json.Marshal(acOut)
	require.NoError(t, err)

	prompt := BuildReviewPromptBounded(b, 1, "abc123", "", t.TempDir(), nil,
		BuildReviewPromptOptions{ACCheckJSON: acJSON}).Prompt

	assert.Contains(t, prompt, "<ac-check>", "review prompt must include <ac-check> section")
	assert.Contains(t, prompt, "TestFoo", "ac-check evidence must be present in prompt")
	assert.Contains(t, prompt, "judgment_overrides", "prompt instructions must describe judgment_overrides override path")
}

// TestReviewer_RatifiesACCheck_Fail_BlocksByRatification verifies that when
// the reviewer emits a BLOCK verdict with structured per-AC evidence citing
// an AC failure, ClassifyReviewFindings returns fixable_gap (repair eligible).
func TestReviewer_RatifiesACCheck_Fail_BlocksByRatification(t *testing.T) {
	res := &ReviewResult{
		Verdict: VerdictBlock,
		PerAC: []ReviewAC{
			{
				Number:   1,
				Item:     "TestBar passes",
				Grade:    "BLOCK",
				Evidence: "AC #1 fail: TestBar did not pass; test not found in diff",
			},
		},
		Findings: []Finding{
			{Severity: "block", Summary: "AC-check reports TestBar fail; add the missing test", Location: "cli/internal/foo/foo_test.go"},
		},
	}

	got := ClassifyReviewFindings(res)
	assert.Equal(t, ReviewFindingClassFixableGap, got.Class)
	assert.True(t, got.AutomatedRepairEligible)
	require.NotEmpty(t, got.Evidence)
}

// TestReviewer_NeedsJudgment_AdjudicatedOrClarification verifies that
// ClassifyReviewFindings treats VerdictRequestClarification as a valid
// operator-routing verdict — not a malfunction — returning an empty class.
func TestReviewer_NeedsJudgment_AdjudicatedOrClarification(t *testing.T) {
	res := &ReviewResult{
		Verdict:  VerdictRequestClarification,
		Rationale: "AC #2 needs clarification: the requirement is ambiguous",
		PerAC: []ReviewAC{
			{Number: 2, Item: "retain_days behaviour", Grade: "REQUEST_CLARIFICATION",
				Evidence: "needs_judgment: no mechanical anchor; defer to reviewer judgment"},
		},
	}

	got := ClassifyReviewFindings(res)
	assert.Empty(t, got.Class, "REQUEST_CLARIFICATION must not be classified as malfunction")
	assert.False(t, got.AutomatedRepairEligible)
}

// TestReviewer_RequestClarification_NotBlockingQueue verifies that a
// REQUEST_CLARIFICATION verdict parks the bead to the operator lane without
// scheduling a repair or blocking the drain queue further.
func TestReviewer_RequestClarification_NotBlockingQueue(t *testing.T) {
	store, first, _ := newExecuteLoopTestStore(t)

	reviewer := beadReviewerFunc(func(_ context.Context, _, _ string, _ ImplementerRouting) (*ReviewResult, error) {
		return &ReviewResult{
			Verdict:   VerdictRequestClarification,
			Rationale: "AC #2 needs operator clarification",
			PerAC: []ReviewAC{
				{Number: 2, Item: "retain_days", Grade: "REQUEST_CLARIFICATION",
					Evidence: "needs_judgment: no mechanical anchor"},
			},
			ReviewerHarness: "claude",
			ReviewerModel:   "claude-opus-4-7",
			ResultRev:       "clarify01",
		}, nil
	})

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	out := RunPostMergeReview(context.Background(), PostMergeReviewInput{
		Bead: *first,
		Report: ExecuteBeadReport{
			BeadID:    first.ID,
			Status:    ExecuteBeadStatusSuccess,
			SessionID: "sess-clarify",
			ResultRev: "clarify01",
			BaseRev:   "clarify00",
		},
		Reviewer: reviewer,
		Store:    store,
		Rcfg:     rcfg,
		Assignee: "worker",
	})

	assert.False(t, out.Approved, "REQUEST_CLARIFICATION must not approve")
	assert.Nil(t, out.RepairContext, "REQUEST_CLARIFICATION must not schedule automated repair")
	assert.Equal(t, ExecuteBeadStatusReviewRequestClarification, out.Report.Status)

	// Verify the bead is parked (moved back to proposed state).
	got, err := store.Get(first.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusProposed, got.Status, "bead must be parked to proposed on REQUEST_CLARIFICATION")
}

// TestReviewer_OverridePassToBlock_RequiresJudgmentReason verifies that
// ParseReviewVerdict correctly decodes judgment_overrides entries, and that the
// review prompt's instructions include the judgment_overrides contract so the
// reviewer knows to supply a non-empty reason + diff_citation when overriding.
func TestReviewer_OverridePassToBlock_RequiresJudgmentReason(t *testing.T) {
	raw := `{
		"schema_version": 1,
		"verdict": "BLOCK",
		"summary": "override mechanical pass: retain_days not wired",
		"per_ac": [{"number": 3, "item": "retain_days wired", "grade": "BLOCK", "evidence": "symbol present but not connected"}],
		"judgment_overrides": [
			{"ac": 3, "reason": "symbol exists but is never read at runtime", "diff_citation": "+retain_days = 0 // dead code"}
		]
	}`

	rv, err := ParseReviewVerdict([]byte(raw))
	require.NoError(t, err)
	assert.Equal(t, VerdictBlock, rv.Verdict)
	require.Len(t, rv.JudgmentOverrides, 1)
	assert.Equal(t, 3, rv.JudgmentOverrides[0].AC)
	assert.NotEmpty(t, rv.JudgmentOverrides[0].Reason, "override must carry a non-empty reason")
	assert.NotEmpty(t, rv.JudgmentOverrides[0].DiffCitation, "override must carry a diff_citation")

	// Verify the prompt instructions surface the judgment_overrides contract.
	b := &bead.Bead{ID: "ddx-override-test", Title: "override pass to block"}
	prompt := BuildReviewPrompt(b, 1, "abc", "", t.TempDir(), nil)
	assert.Contains(t, strings.ToLower(prompt), "judgment_overrides",
		"review prompt must describe the judgment_overrides field for override path")
	assert.Contains(t, strings.ToLower(prompt), "diff_citation",
		"review prompt must require diff_citation for overrides")
}

// TestReviewer_StrictnessMode_KindFix_RequiresTestNames verifies that kind:fix
// beads receive the strict strictness mode, which requires test-name evidence.
func TestReviewer_StrictnessMode_KindFix_RequiresTestNames(t *testing.T) {
	assert.Equal(t, StrictnessStrict, BeadStrictnessMode([]string{"kind:fix"}))
	assert.Equal(t, StrictnessStrict, BeadStrictnessMode([]string{"kind:feat"}))
	assert.Equal(t, StrictnessStrict, BeadStrictnessMode(nil), "default must be strict")

	b := &bead.Bead{ID: "ddx-strict", Title: "fix: add TestBaz", Labels: []string{"kind:fix"}}
	prompt := BuildReviewPrompt(b, 1, "abc", "", t.TempDir(), nil)
	assert.Contains(t, prompt, "strict", "kind:fix review prompt must mention strict mode")
	assert.Contains(t, prompt, "Test", "strict mode must require test evidence language")
}

// TestReviewer_StrictnessMode_KindRefactor_BuildGreenSuffices verifies that
// kind:refactor beads receive the behavior-light strictness mode.
func TestReviewer_StrictnessMode_KindRefactor_BuildGreenSuffices(t *testing.T) {
	assert.Equal(t, StrictnessBehaviorLight, BeadStrictnessMode([]string{"kind:refactor"}))
	assert.Equal(t, StrictnessBehaviorLight, BeadStrictnessMode([]string{"kind:chore"}))

	b := &bead.Bead{ID: "ddx-refactor", Title: "refactor: rename foo", Labels: []string{"kind:refactor"}}
	prompt := BuildReviewPrompt(b, 1, "abc", "", t.TempDir(), nil)
	assert.Contains(t, prompt, "behavior-light", "kind:refactor review prompt must mention behavior-light mode")
}

// TestReviewer_StrictnessMode_KindDoc_FilePresenceSuffices verifies that
// kind:doc and kind:mechanical beads receive the mechanical strictness mode.
func TestReviewer_StrictnessMode_KindDoc_FilePresenceSuffices(t *testing.T) {
	assert.Equal(t, StrictnessMechanical, BeadStrictnessMode([]string{"kind:doc"}))
	assert.Equal(t, StrictnessMechanical, BeadStrictnessMode([]string{"kind:mechanical"}))

	b := &bead.Bead{ID: "ddx-doc", Title: "doc: update README", Labels: []string{"kind:doc"}}
	prompt := BuildReviewPrompt(b, 1, "abc", "", t.TempDir(), nil)
	assert.Contains(t, prompt, "mechanical", "kind:doc review prompt must mention mechanical mode")
	assert.Contains(t, prompt, "file presence", "mechanical mode must describe file-presence check")
}

// TestImplementerFlow_ACCheckFail_AbortsWithoutWaive verifies that
// ShouldAbortForACCheckFail returns true when there is at least one fail result
// and no AC-Waive: trailer in the commit message. Also tests BuildACCheckTrailer.
func TestImplementerFlow_ACCheckFail_AbortsWithoutWaive(t *testing.T) {
	output := &accheck.Output{
		BeadID:  "ddx-abort-test",
		Summary: accheck.Summary{Pass: 1, Fail: 1},
	}

	trailer := BuildACCheckTrailer(output.Summary)
	assert.Contains(t, trailer, "AC-Check:", "trailer must start with AC-Check:")
	assert.Contains(t, trailer, "pass=1", "trailer must include pass count")
	assert.Contains(t, trailer, "fail=1", "trailer must include fail count")

	commitMsg := "chore: execute-bead iteration ddx-abort-test\n\n" + trailer
	assert.True(t, ShouldAbortForACCheckFail(output, commitMsg),
		"must abort when fail > 0 and no AC-Waive trailer")

	// Nil output and zero-fail output must never abort.
	assert.False(t, ShouldAbortForACCheckFail(nil, commitMsg))
	assert.False(t, ShouldAbortForACCheckFail(&accheck.Output{Summary: accheck.Summary{Pass: 2}}, commitMsg))
}

// TestImplementerFlow_ACWaiveTrailer_PassesAttempt verifies that an AC-Waive:
// trailer in the commit message suppresses the abort even when fail > 0.
func TestImplementerFlow_ACWaiveTrailer_PassesAttempt(t *testing.T) {
	output := &accheck.Output{
		BeadID:  "ddx-waive-test",
		Summary: accheck.Summary{Pass: 0, Fail: 2},
	}

	commitMsgWithWaive := "chore: execute-bead iteration ddx-waive-test\n\n" +
		BuildACCheckTrailer(output.Summary) + "\nAC-Waive: operator approved despite ac-check failures"

	assert.False(t, ShouldAbortForACCheckFail(output, commitMsgWithWaive),
		"AC-Waive trailer must suppress abort")

	// Waive with leading whitespace is still recognised.
	commitMsgIndented := "chore: execute-bead iteration ddx-waive-test\n\n  AC-Waive: indented"
	assert.False(t, ShouldAbortForACCheckFail(output, commitMsgIndented))
}

// TestReviewer_RegressionFakeRetainDays_BlocksByACCheck is a regression test
// that guards against a past mis-classification: a review that blocks because
// the implementation adds a fake/dead `retain_days` property without actually
// wiring it must be classified as fixable_gap (not a terminal class or
// malfunction), so the drain queue can schedule a repair attempt.
func TestReviewer_RegressionFakeRetainDays_BlocksByACCheck(t *testing.T) {
	// Simulate a reviewer that saw an ac-check fail for retain_days wiring
	// and emitted a BLOCK verdict with structured per-AC evidence.
	res := &ReviewResult{
		Verdict: VerdictBlock,
		PerAC: []ReviewAC{
			{
				Number:   3,
				Item:     "retain_days field is wired and read at call sites",
				Grade:    "BLOCK",
				Evidence: "AC #3 fail: retain_days present in diff but no call site reads it",
			},
		},
		Findings: []Finding{
			{Severity: "block", Summary: "fake retain_days: field added but never consumed; AC check fails", Location: "cli/internal/foo/config.go:42"},
		},
	}

	got := ClassifyReviewFindings(res)
	assert.Equal(t, ReviewFindingClassFixableGap, got.Class,
		"retain_days wiring gap must classify as fixable_gap, not terminal")
	assert.True(t, got.AutomatedRepairEligible,
		"fixable ac-check gap must be eligible for automated repair")
	require.NotEmpty(t, got.Evidence)
}

